type Item = ...;  // not counted (type only)

const itemBasePremium = (item: Item): number =>
  BASE_PREMIUM[item.type] ?? 0;
  // bindings: item (1)
  // invocations: BASE_PREMIUM[item.type] property access (2), ?? (2)
  // constants: 0 (1)
